def InvOrdinalDay(Number: Int, mut PMonth: Int, mut PDay: Int, LeapYr: Int):
    var EndOfMonth: List[Int] = [0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334, 365]
    var WMonth: Int = 0
    var LeapAddPrev: Int = 0
    var LeapAddCur: Int = 0
    if Number < 0 or Number > 366:
        return
    WMonth = 1
    while WMonth <= 12:
        if WMonth == 1:
            LeapAddPrev = 0
            LeapAddCur = 0
        elif WMonth == 2:
            LeapAddPrev = 0
            LeapAddCur = LeapYr
        else:
            LeapAddPrev = LeapYr
            LeapAddCur = LeapYr
        if Number > (EndOfMonth[WMonth - 1] + LeapAddPrev) and Number <= (EndOfMonth[WMonth] + LeapAddCur):
            break
        WMonth += 1
    PMonth = WMonth
    PDay = Number - (EndOfMonth[WMonth - 1] + LeapAddCur)

