def GetProfIndices(profAng: Float64, mut idxLo: Int, mut idxHi: Int):
    idxLo = Int((profAng + 3.14159265358979324 / 2.0) / (3.14159265358979324 / 36.0)) + 1
    idxHi = min(37, idxLo + 1)

